# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, Props}

case class Deposit(amount: BigDecimal)
case class Withdrawal(amount: BigDecimal)

class AccountManager extends Actor {
  private var balance = BigDecimal(0)

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! BalanceUpdated(balance)
    case Withdrawal(amount) if amount <= balance =>
      balance -= amount
      sender() ! BalanceUpdated(balance)
    case Withdrawal(_) =>
      sender() ! InsufficientFunds
  }

  case class BalanceUpdated(newBalance: BigDecimal)
  case object InsufficientFunds
}

object AccountManager {
  def props: Props = Props[AccountManager]
}